import sys
from pathlib import Path

import pandas as pd

# Allow running as a top-level script from the workspace root
sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from app.database import Base, engine
from app.models import Combo, ComboPerformance, Part  # noqa: F401 – needed for metadata

# ---------------------------------------------------------------------------
# Paths
# ---------------------------------------------------------------------------
_ROOT = Path(__file__).resolve().parent.parent
_PARTS_CSV = _ROOT / "beyblade_parts.csv"
_COMBOS_CSV = _ROOT / "combos.csv"
_PERF_CSV = _ROOT / "combo_performance.csv"


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _to_bool(val) -> bool | None:
    """Convert truthy string values to Python bool."""
    if pd.isna(val):
        return None
    if isinstance(val, bool):
        return val
    return str(val).strip().lower() in {"true", "1", "yes"}


def _to_int_or_none(val) -> int | None:
    """Coerce to int, returning None for NaN / non-numeric values."""
    try:
        if pd.isna(val):
            return None
        return int(float(val))
    except (TypeError, ValueError):
        return None


def _to_float_or_none(val) -> float | None:
    """Coerce to float, returning None for NaN / non-numeric values."""
    try:
        if pd.isna(val):
            return None
        return float(val)
    except (TypeError, ValueError):
        return None


def _normalize_type(val: str | None) -> str | None:
    """Fix known typos in the 'type' controlled vocabulary."""
    if not val or (isinstance(val, float)):
        return None
    mapping = {"balacne": "Balance", "balance": "Balance"}
    cleaned = str(val).strip()
    return mapping.get(cleaned.lower(), cleaned)


# ---------------------------------------------------------------------------
# Loaders
# ---------------------------------------------------------------------------

def _load_parts(session) -> int:
    """Read beyblade_parts.csv and bulk-insert Part rows."""
    df = pd.read_csv(_PARTS_CSV, dtype=str)

    parts = []
    for _, row in df.iterrows():
        parts.append(
            Part(
                part_id=row["part_id"],
                name=row["name"],
                category=row.get("category"),
                is_beyblade_part=_to_bool(row.get("is_beyblade_part")),
                product_code_full=row.get("product_code_full"),
                product_line=row.get("product_line"),
                product_number=row.get("product_number"),
                source_url=row.get("source_url"),
                variant_count=_to_int_or_none(row.get("variant_count")),
                type=_normalize_type(row.get("type")),
                spin=row.get("spin") if pd.notna(row.get("spin")) else None,
                weight_g=_to_float_or_none(row.get("weight_g")),
                contact_points=_to_int_or_none(row.get("contact_points")),
                height_mm=_to_float_or_none(row.get("height_mm")),
                gears=_to_int_or_none(row.get("gears")),
                burst_resistance=row.get("burst_resistance") if pd.notna(row.get("burst_resistance")) else None,
                stock_combo=row.get("stock_combo") if pd.notna(row.get("stock_combo")) else None,
                stock_combo_ratchet=row.get("stock_combo_ratchet") if pd.notna(row.get("stock_combo_ratchet")) else None,
                stock_combo_bit=row.get("stock_combo_bit") if pd.notna(row.get("stock_combo_bit")) else None,
                high_level_mm=_to_float_or_none(row.get("high_level_mm")),
            )
        )

    session.bulk_save_objects(parts)
    return len(parts)


