                ratchet=row.get("ratchet") if pd.notna(row.get("ratchet")) else None,
                bit=row.get("bit") if pd.notna(row.get("bit")) else None,
                lock_chip=row.get("lock_chip") if pd.notna(row.get("lock_chip")) else None,
                blade_type=_normalize_type(row.get("blade_type")),
                blade_spin=row.get("blade_spin") if pd.notna(row.get("blade_spin")) else None,
                blade_weight_g=_to_float_or_none(row.get("blade_weight_g")),
