                ratchet_burst_resistance=row.get("ratchet_burst_resistance") if pd.notna(row.get("ratchet_burst_resistance")) else None,
                bit_type=_normalize_type(row.get("bit_type")),
                bit_weight_g=_to_float_or_none(row.get("bit_weight_g")),
